   201→    // Check recruiter auth
   202→    document.addEventListener('DOMContentLoaded', async () => {
   203→      const user = await checkAuth();
   204→      if (!user) {
   205→        window.location.href = '/login.html';
   206→        return;
   207→      }
   208→
   209→      // Verify recruiter role
   210→      if (!user.company_id && user.role !== 'recruiter') {
   211→        window.location.href = '/dashboard.html';
   212→        return;
   213→      }
   214→
   215→      // Update user info
   216→      const name = user.name || user.email.split('@')[0];
   217→      document.getElementById('user-name').textContent = name;
   218→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   219→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   220→      document.getElementById('dropdown-user-name').textContent = name;
   221→      document.getElementById('dropdown-user-email').textContent = user.email;
   222→
   223→      // Setup user menu dropdown
   224→      const userMenuToggle = document.getElementById('user-menu-toggle');
   225→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   226→      if (userMenuToggle && userDropdownMenu) {
   227→        userMenuToggle.addEventListener('click', (e) => {
   228→          e.stopPropagation();
   229→          userDropdownMenu.classList.toggle('active');
   230→        });
   231→
   232→        document.addEventListener('click', () => {
   233→          userDropdownMenu.classList.remove('active');
   234→        });
   235→
   236→        userDropdownMenu.addEventListener('click', (e) => {
   237→          e.stopPropagation();
   238→        });
   239→      }
   240→
   241→      // Load dashboard data
   242→      loadRecruiterDashboard();
   243→    });
   244→
   245→    async function loadRecruiterDashboard() {
   246→      try {
   247→        const data = await apiCall('/recruiter/dashboard');
   248→        if (!data) return;
   249→
   250→        // Update TrustScore
   251→        if (data.trust_score) {
   252→          document.getElementById('trustscore-value').textContent = data.trust_score.total_score;
   253→          document.getElementById('trustscore-tier').textContent = data.trust_score.tier_label;
   254→          document.getElementById('trustscore-tier').style.background = data.trust_score.tier_color;
   255→        }
   256→
   257→        // Update stats
   258→        document.getElementById('active-jobs').textContent = data.job_stats?.active_jobs || 0;
   259→        document.getElementById('total-applications').textContent = data.application_stats?.total_applications || 0;
   260→        document.getElementById('new-applications').textContent = data.application_stats?.new_applications || 0;
   261→
   262→        const interviewed = parseInt(data.application_stats?.interviewed) || 0;
   263→        const offered = parseInt(data.application_stats?.offered) || 0;
   264→        const ratio = interviewed > 0 ? ((offered / interviewed) * 100).toFixed(0) + '%' : '-';
   265→        document.getElementById('offer-ratio').textContent = ratio;
   266→
   267→        // Render upcoming interviews
   268→        renderUpcomingInterviews(data.upcoming_interviews || []);
   269→
   270→        // Render recent applications
   271→        renderRecentApplications(data.recent_applications || []);
   272→
   273→      } catch (err) {
   274→        console.error('Failed to load dashboard:', err);
   275→      }
   276→    }
   277→
   278→    function renderUpcomingInterviews(interviews) {
   279→      const container = document.getElementById('upcoming-interviews');
   280→
   281→      if (interviews.length === 0) {
   282→        container.innerHTML = `
   283→          <div class="empty-state">
   284→            <p>No upcoming interviews</p>
   285→            <a href="/recruiter-applications.html" class="btn btn-ghost btn-sm">Review applications</a>
   286→          </div>
   287→        `;
   288→        return;
   289→      }
   290→
   291→      container.innerHTML = interviews.map(i => `
   292→        <div class="interview-item">
   293→          <div class="interview-time">
   294→            <span class="date">${new Date(i.scheduled_at).toLocaleDateString()}</span>
   295→            <span class="time">${new Date(i.scheduled_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
   296→          </div>
   297→          <div class="interview-info">
   298→            <span class="candidate-name">${i.candidate_name}</span>
   299→            <span class="job-title">${i.job_title}</span>
   300→          </div>
   301→          <span class="interview-type-badge ${i.interview_type}">${i.interview_type}</span>
   302→        </div>
   303→      `).join('');
   304→    }
   305→
   306→    function renderRecentApplications(applications) {
   307→      const container = document.getElementById('recent-applications');
   308→
   309→      if (applications.length === 0) {
   310→        container.innerHTML = `
   311→          <div class="empty-state">
   312→            <p>No applications yet</p>
   313→            <a href="/job-create.html" class="btn btn-ghost btn-sm">Post a job</a>
   314→          </div>
   315→        `;
   316→        return;
   317→      }
   318→
   319→      container.innerHTML = applications.map(a => `
   320→        <div class="application-item">
   321→          <div class="candidate-info">
   322→            <span class="candidate-name">${a.candidate_name}</span>
   323→            <span class="job-title">${a.job_title}</span>
   324→          </div>
   325→          <div class="application-meta">
   326→            ${a.omniscore_at_apply ? `<span class="omniscore-badge">${a.omniscore_at_apply} OmniScore</span>` : ''}
   327→            <span class="status-badge ${a.status}">${a.status}</span>
   328→          </div>
   329→        </div>
   330→      `).join('');
   331→    }
