   274→      if (userMenuToggle && userDropdownMenu) {
   275→        userMenuToggle.addEventListener('click', (e) => {
   276→          e.stopPropagation();
   277→          userDropdownMenu.classList.toggle('active');
   278→        });
   279→
   280→        document.addEventListener('click', () => {
   281→          userDropdownMenu.classList.remove('active');
