   292→    async function loadCompanyProfile() {
   293→      try {
   294→        const data = await apiCall('/company/profile');
   295→        if (!data) return;
   296→
   297→        companyData = data.company;
   298→        populateForm(companyData);
   299→        updateCompleteness(companyData);
   300→      } catch (err) {
   301→        console.error('Failed to load profile:', err);
   302→      }
   303→    }
   304→
   305→    function populateForm(company) {
   306→      const form = document.getElementById('profile-form');
   307→      form.name.value = company.name || '';
   308→      form.description.value = company.description || '';
   309→      form.industry.value = company.industry || '';
   310→      form.company_size.value = company.company_size || '';
   311→      form.headquarters.value = company.headquarters || '';
   312→      form.founded_year.value = company.founded_year || '';
   313→      form.website.value = company.website || '';
   314→      form.linkedin_url.value = company.linkedin_url || '';
   315→      form.logo_url.value = company.logo_url || '';
   316→      form.culture_description.value = company.culture_description || '';
   317→
   318→      // Update logo preview
   319→      if (company.logo_url) {
   320→        document.getElementById('logo-preview').innerHTML =
   321→          `<img src="${company.logo_url}" alt="Company logo" onerror="this.parentElement.innerHTML='<div class=\\'logo-placeholder\\'>Invalid URL</div>'">`;
   322→      }
   323→
   324→      // Load values, benefits, locations from JSON fields
   325→      values = company.core_values ? JSON.parse(company.core_values) : [];
   326→      benefits = company.benefits ? JSON.parse(company.benefits) : [];
   327→      locations = company.office_locations ? JSON.parse(company.office_locations) : [];
   328→
   329→      renderTags('values-list', values, removeValue);
   330→      renderTags('benefits-list', benefits, removeBenefit);
   331→      renderTags('locations-list', locations, removeLocation);
   332→    }
   333→
   334→    function updateCompleteness(company) {
   335→      const fields = [
   336→        company.name,
   337→        company.description,
   338→        company.industry,
   339→        company.company_size,
   340→        company.headquarters,
   341→        company.website,
   342→        company.logo_url,
   343→        company.linkedin_url,
   344→        company.culture_description,
   345→        company.core_values && JSON.parse(company.core_values).length > 0,
   346→        company.benefits && JSON.parse(company.benefits).length > 0,
   347→        company.office_locations && JSON.parse(company.office_locations).length > 0
   348→      ];
   349→
   350→      const completed = fields.filter(f => f && (typeof f === 'boolean' ? f : f.length > 0)).length;
   351→      const percentage = Math.round((completed / fields.length) * 100);
   352→
   353→      document.getElementById('completeness-fill').style.width = percentage + '%';
   354→      document.getElementById('completeness-percent').textContent = percentage + '%';
   355→
   356→      if (percentage === 100) {
   357→        document.getElementById('completeness-card').classList.add('complete');
   358→      }
   359→    }
