   361→    function renderTags(containerId, items, removeFunc) {
   362→      const container = document.getElementById(containerId);
   363→      if (items.length === 0) {
   364→        container.innerHTML = '<p class="empty-tags">None added yet</p>';
   365→        return;
   366→      }
   367→      container.innerHTML = items.map((item, idx) => `
   368→        <span class="tag">
   369→          ${item}
   370→          <button type="button" onclick="${removeFunc.name}(${idx})" class="tag-remove">×</button>
   371→        </span>
   372→      `).join('');
   373→    }
