   375→    function addValue() {
   376→      const input = document.getElementById('value-input');
   377→      const value = input.value.trim();
   378→      if (value && values.length < 5 && !values.includes(value)) {
   379→        values.push(value);
   380→        renderTags('values-list', values, removeValue);
   381→        input.value = '';
   382→      }
   383→    }
