   431→    document.getElementById('profile-form').addEventListener('submit', async (e) => {
   432→      e.preventDefault();
   433→      const form = e.target;
   434→      const submitBtn = form.querySelector('button[type="submit"]');
   435→      const message = document.getElementById('form-message');
   436→
   437→      submitBtn.disabled = true;
   438→      submitBtn.textContent = 'Saving...';
   439→
   440→      try {
   441→        const response = await apiCall('/company/profile', {
   442→          method: 'PUT',
   443→          body: JSON.stringify({
   444→            name: form.name.value,
   445→            description: form.description.value,
   446→            industry: form.industry.value,
   447→            company_size: form.company_size.value,
   448→            headquarters: form.headquarters.value,
   449→            founded_year: form.founded_year.value ? parseInt(form.founded_year.value) : null,
   450→            website: form.website.value,
   451→            linkedin_url: form.linkedin_url.value,
   452→            logo_url: form.logo_url.value,
   453→            culture_description: form.culture_description.value,
   454→            core_values: JSON.stringify(values),
   455→            benefits: JSON.stringify(benefits),
   456→            office_locations: JSON.stringify(locations)
   457→          })
   458→        });
   459→
   460→        if (response.success) {
   461→          message.textContent = '✅ Profile updated successfully!';
   462→          message.className = 'form-message success';
   463→          message.style.display = 'block';
   464→
   465→          // Update completeness
   466→          if (response.company) {
   467→            updateCompleteness(response.company);
