   469→
   470→          setTimeout(() => {
   471→            message.style.display = 'none';
   472→          }, 3000);
   473→        } else {
   474→          throw new Error(response.error || 'Failed to update profile');
   475→        }
   476→      } catch (err) {
   477→        message.textContent = '❌ ' + err.message;
   478→        message.className = 'form-message error';
